  const idempotencyKey = config.headers?.['X-Idempotency-Key'] || makeIdempotencyKey()
  const safeHeaders = {
    'X-Idempotency-Key': idempotencyKey,
    ...(config.headers?.['Content-Type'] ? { 'Content-Type': config.headers['Content-Type'] } : {}),
  }

  await enqueuePendingAction({
    id: `${Date.now()}-${Math.random().toString(36).slice(2)}`,
    url: config.url,
    method: String(config.method).toUpperCase(),
    data: config.data ?? null,
    headers: safeHeaders,
    owner_key: currentOwnerKey(),
    timestamp: Date.now(),
  })

  return queuedResponse({
    ...config,
    headers: safeHeaders,
  })
}

const markSyncFailure = (action, reason) => {
  sessionStorage.setItem('roadlink_toast_message', `Error syncing offline action (${action.method} ${action.url}): ${reason}`)
  sessionStorage.setItem('roadlink_toast_type', 'error')
