            ], 422);
        }

        return response()->json(['order' => $order->load(['auditLogs' => fn ($query) => $query->orderBy('created_at')])]);
    }

    public function cancel(FleetRideCancelRequest $request, RideOrder $rideOrder): JsonResponse
    {
